124→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
125→  return {
126→    onMouseDown(modelPos, e, toolState) {
127→      if (e.button !== 0) return;
128→
129→      const floor = getFloor(activeFloorId);
130→      if (!floor) return;
131→
132→      // Check if clicking a handle
133→      const target = e.target;
134→      if (target.dataset.handle) {
135→        editorDispatch({
136→          type: 'UPDATE_TOOL_STATE',
137→          payload: {
138→            dragging: true,
139→            dragType: 'handle',
140→            handle: target.dataset.handle,
141→            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
142→            startPos: modelPos,
143→          },
144→        });
145→        return;
146→      }
147→
148→      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
149→      if (hit) {
150→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
151→        const draggableTypes = new Set(['wall', 'column', 'fixture', 'door', 'window', 'stair', 'sectionCut', 'landing', 'railing']);
152→        if (!draggableTypes.has(hit.type)) return;
153→        editorDispatch({
154→          type: 'UPDATE_TOOL_STATE',
155→          payload: {
156→            pendingDrag: true,
157→            dragging: false,
158→            dragType: 'move',
159→            startPos: modelPos,
160→            originalPos: modelPos,
161→          },
162→        });
163→      } else {
164→        editorDispatch({
165→          type: 'UPDATE_TOOL_STATE',
166→          payload: {
167→            dragging: true,
168→            dragType: 'marquee',
169→            startPos: modelPos,
170→            currentPos: modelPos,
171→          },
172→        });
173→      }
174→    },
175→
176→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
177→      const DRAG_THRESHOLD_PX = 4;
178→
179→      if (toolState.pendingDrag && !toolState.dragging) {
180→        const dx = modelPos.x - toolState.startPos.x;
181→        const dy = modelPos.y - toolState.startPos.y;
182→        const distPx = Math.sqrt(dx * dx + dy * dy) * viewport.zoom;
183→        if (distPx < DRAG_THRESHOLD_PX) return;
184→        editorDispatch({
185→          type: 'UPDATE_TOOL_STATE',
186→          payload: { pendingDrag: false, dragging: true },
187→        });
188→      }
189→
190→      if (toolState.dragging && toolState.dragType === 'marquee') {
191→        editorDispatch({
192→          type: 'UPDATE_TOOL_STATE',
193→          payload: { currentPos: modelPos },
194→        });
195→        return;
196→      }
197→
198→      if (!toolState.dragging || !selectedId) return;
199→
200→      const floor = getFloor(activeFloorId);
201→      if (!floor) return;
202→      const dx = modelPos.x - toolState.startPos.x;
203→      const dy = modelPos.y - toolState.startPos.y;
204→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
205→
206→      if (selectedType === 'wall') {
207→        const wall = floor.walls.find(w => w.id === selectedId);
208→        if (!wall) return;
209→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
210→
211→        if (toolState.dragType === 'handle') {
212→          const handle = toolState.handle;
213→          const oppositeKey = handle === 'start' ? 'end' : 'start';
214→          const oppositePoint = resolved[oppositeKey];
215→          let nextPoint = modelPos;
216→          let nextAttachment = null;
217→
218→          if (e.shiftKey) {
219→            const dx = modelPos.x - oppositePoint.x;
220→            const dy = modelPos.y - oppositePoint.y;
221→            const angle = Math.atan2(dy, dx);
222→            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
223→            const len = Math.sqrt(dx * dx + dy * dy);
224→            nextPoint = {
225→              x: oppositePoint.x + Math.cos(snapAngle) * len,
226→              y: oppositePoint.y + Math.sin(snapAngle) * len,
227→            };
228→          } else if (snapEnabled) {
229→            const snapResult = snapWallEndpoint(modelPos, {
230→              walls: floor.walls,
231→              columns: floor.columns || [],
232→              snapDist: snapDistModel,
233→              otherPoint: oppositePoint,
234→              ignoreWallId: wall.id,
235→            });
236→            if (snapResult) {
237→              nextPoint = snapResult.point;
238→              nextAttachment = snapResult.attachment;
239→            }
240→          }
241→
242→          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;
243→
244→          dispatch({
245→            type: 'WALL_UPDATE',
246→            floorId: activeFloorId,
247→            wall: {
248→              id: wall.id,
249→              [handle]: nextPoint,
250→              [`${handle}Attachment`]: nextAttachment,
251→            },
252→          });
253→        } else {
254→          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
255→          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
256→          let startAttachment = null;
257→          let endAttachment = null;
258→
259→          if (snapEnabled) {
260→            const startSnap = snapWallEndpoint(nextStart, {
261→              walls: floor.walls,
262→              columns: floor.columns || [],
263→              snapDist: snapDistModel,
264→              otherPoint: nextEnd,
265→              ignoreWallId: wall.id,
266→            });
267→            if (startSnap) {
268→              nextStart = startSnap.point;
269→              startAttachment = startSnap.attachment;
270→            }
271→
272→            const endSnap = snapWallEndpoint(nextEnd, {
273→              walls: floor.walls,
274→              columns: floor.columns || [],
275→              snapDist: snapDistModel,
276→              otherPoint: nextStart,
277→              ignoreWallId: wall.id,
278→            });
279→            if (endSnap) {
280→              nextEnd = endSnap.point;
281→              endAttachment = endSnap.attachment;
282→            }
283→          }
284→
285→          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;
286→
287→          dispatch({
288→            type: 'WALL_UPDATE',
289→            floorId: activeFloorId,
290→            wall: {
291→              id: wall.id,
292→              start: nextStart,
293→              end: nextEnd,
294→              startAttachment,
295→              endAttachment,
296→            },
297→          });
298→        }
299→        editorDispatch({
300→          type: 'UPDATE_TOOL_STATE',
301→          payload: { startPos: modelPos },
302→        });
303→      } else if (selectedType === 'column') {
304→        const col = (floor.columns || []).find(c => c.id === selectedId);
305→        if (!col) return;
306→        dispatch({
307→          type: 'COLUMN_UPDATE',
308→          floorId: activeFloorId,
309→          column: { id: col.id, x: col.x + dx, y: col.y + dy },
310→        });
311→        editorDispatch({
312→          type: 'UPDATE_TOOL_STATE',
313→          payload: { startPos: modelPos },
314→        });
315→      } else if (selectedType === 'fixture') {
316→        const fixture = (floor.fixtures || []).find(f => f.id === selectedId);
317→        if (!fixture) return;
318→        dispatch({
319→          type: 'FIXTURE_UPDATE',
320→          floorId: activeFloorId,
321→          fixture: { id: fixture.id, x: fixture.x + dx, y: fixture.y + dy },
322→        });
323→        editorDispatch({
324→          type: 'UPDATE_TOOL_STATE',
325→          payload: { startPos: modelPos },
326→        });
327→      } else if (selectedType === 'sectionCut') {
328→        const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId);
329→        if (!sectionCut) return;
330→
331→        if (toolState.dragType === 'handle') {
332→          const handle = toolState.handle;
333→          const nextSectionCut = handle === 'start'
334→            ? { ...sectionCut, startPoint: modelPos }
335→            : { ...sectionCut, endPoint: modelPos };
336→
337→          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;
338→
339→          dispatch({
340→            type: 'SECTION_UPDATE',
341→            floorId: activeFloorId,
342→            sectionCut: nextSectionCut,
343→          });
344→        } else {
345→          dispatch({
346→            type: 'SECTION_UPDATE',
347→            floorId: activeFloorId,
348→            sectionCut: {
349→              id: sectionCut.id,
350→              startPoint: {
351→                x: sectionCut.startPoint.x + dx,
352→                y: sectionCut.startPoint.y + dy,
353→              },
354→              endPoint: {
355→                x: sectionCut.endPoint.x + dx,
356→                y: sectionCut.endPoint.y + dy,
357→              },
358→            },
359→          });
360→          editorDispatch({
361→            type: 'UPDATE_TOOL_STATE',
362→            payload: { startPos: modelPos },
363→          });
364→        }
365→      } else if (selectedType === 'railing') {
366→        const railing = (floor.railings || []).find(r => r.id === selectedId);
367→        if (!railing) return;
368→
369→        if (toolState.dragType === 'handle') {
370→          const handle = toolState.handle;
371→          const nextRailing = handle === 'start'
372→            ? { ...railing, startPoint: modelPos }
373→            : { ...railing, endPoint: modelPos };
374→
375→          if (distance(nextRailing.startPoint, nextRailing.endPoint) < MIN_WALL_LENGTH) return;
376→
377→          dispatch({
378→            type: 'RAILING_UPDATE',
379→            floorId: activeFloorId,
380→            railing: nextRailing,
381→          });
382→        } else {
383→          dispatch({
384→            type: 'RAILING_UPDATE',
385→            floorId: activeFloorId,
386→            railing: {
387→              id: railing.id,
388→              startPoint: {
389→                x: railing.startPoint.x + dx,
390→                y: railing.startPoint.y + dy,
391→              },
392→              endPoint: {
393→                x: railing.endPoint.x + dx,
394→                y: railing.endPoint.y + dy,
395→              },
396→            },
397→          });
398→          editorDispatch({
399→            type: 'UPDATE_TOOL_STATE',
400→            payload: { startPos: modelPos },
401→          });
402→        }
403→      } else if (selectedType === 'beam') {
404→        return;
405→      } else if (selectedType === 'stair') {
406→        const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
407→        if (!stair) return;
408→        dispatch({
409→          type: 'STAIR_UPDATE',
410→          floorId: activeFloorId,
411→          stair: {
412→            id: stair.id,
413→            startPoint: {
414→              x: stair.startPoint.x + dx,
415→              y: stair.startPoint.y + dy,
416→            },
417→          },
418→        });
419→        editorDispatch({
420→          type: 'UPDATE_TOOL_STATE',
421→          payload: { startPos: modelPos },
422→        });
423→      } else if (selectedType === 'landing') {
424→        const landing = (floor.landings || []).find(l => l.id === selectedId);
425→        if (!landing) return;
426→        dispatch({
427→          type: 'LANDING_UPDATE',
428→          floorId: activeFloorId,
429→          landing: {
430→            id: landing.id,
431→            position: {
432→              x: landing.position.x + dx,
433→              y: landing.position.y + dy,
434→            },
435→          },
436→        });
437→        editorDispatch({
438→          type: 'UPDATE_TOOL_STATE',
439→          payload: { startPos: modelPos },
440→        });
441→      } else if (selectedType === 'slab') {
442→        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
443→          return;
444→        }
445→        const slab = (floor.slabs || []).find(s => s.id === selectedId);
446→        if (!slab) return;
447→
448→        const boundaryPoints = slab.boundaryPoints.map((point, index) => (
449→          index === toolState.handleIndex ? { x: modelPos.x, y: modelPos.y } : point
450→        ));
451→
452→        dispatch({
453→          type: 'SLAB_UPDATE',
454→          floorId: activeFloorId,
455→          slab: {
456→            id: slab.id,
457→            boundaryPoints,
458→          },
459→        });
460→        editorDispatch({
461→          type: 'UPDATE_TOOL_STATE',
462→          payload: { startPos: modelPos },
463→        });
464→      } else if (selectedType === 'door' || selectedType === 'window') {
465→        // Slide along parent wall
466→        const items = selectedType === 'door' ? floor.doors : floor.windows;
467→        const item = items.find(i => i.id === selectedId);
468→        if (!item) return;
469→
470→        const wall = floor.walls.find(w => w.id === item.wallId);
471→        if (!wall) return;
472→
473→        const newOffset = projectPointOnWall(wall, modelPos);
474→        const clampedOffset = clampWallOpeningOffset(wallLength(wall), item.width, newOffset);
475→
476→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
477→        dispatch({
478→          type: updateType,
479→          floorId: activeFloorId,
480→          [selectedType]: { id: item.id, offset: clampedOffset },
481→        });
482→
483→        editorDispatch({
484→          type: 'UPDATE_TOOL_STATE',
485→          payload: { startPos: modelPos },
486→        });
487→      }
488→    },
489→
490→    onMouseUp(modelPos, e, toolState) {
491→      if (toolState.dragging && toolState.dragType === 'marquee') {
492→        const floor = getFloor(activeFloorId);
493→        const bounds = normalizeRectBounds(toolState.startPos || modelPos, toolState.currentPos || modelPos);
494→        const size = rectSize(bounds);
495→        const minimumSize = SNAP_DISTANCE_PX / viewport.zoom;
496→
497→        if (!floor || (size.width < minimumSize && size.height < minimumSize)) {
498→          editorDispatch({ type: 'DESELECT' });
499→        } else {
500→          const regionSelection = collectPlanRegionSelection(floor, bounds);
501→          if (regionSelection.objectCount) {
502→            editorDispatch({
503→              type: 'SET_REGION_SELECTION',
504→              bounds: regionSelection.bounds,
505→              selection: regionSelection.selection,
506→            });
507→          } else {
508→            editorDispatch({ type: 'DESELECT' });
509→          }
510→        }
511→
512→        editorDispatch({
513→          type: 'UPDATE_TOOL_STATE',
514→          payload: {
515→            dragging: false,
516→            dragType: null,
517→            handle: null,
518→            handleIndex: null,
519→            startPos: null,
520→            currentPos: null,
521→          },
522→        });
523→        return;
524→      }
525→
526→      if (toolState.dragging || toolState.pendingDrag) {
527→        editorDispatch({
528→          type: 'UPDATE_TOOL_STATE',
529→          payload: {
530→            dragging: false,
531→            pendingDrag: false,
532→            dragType: null,
533→            handle: null,
534→            handleIndex: null,
535→            startPos: null,
536→            originalPos: null,
537→            currentPos: null,
538→          },
539→        });
540→      }
541→    },
542→
543→    onKeyDown(e, toolState, selectedId, selectedType) {
544→      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'd' && selectedId && selectedType === 'column') {
545→        e.preventDefault();
546→        const floor = getFloor(activeFloorId);
547→        if (!floor) return;
548→        const column = (floor.columns || []).find(c => c.id === selectedId);
549→        if (!column) return;
550→        const duplicate = duplicateColumn(column);
551→        dispatch({ type: 'COLUMN_DUPLICATE', floorId: activeFloorId, column: duplicate });
552→        editorDispatch({ type: 'SELECT_OBJECT', id: duplicate.id, objectType: 'column' });
553→        return;
554→      }
555→
556→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
557→        const floor = getFloor(activeFloorId);
558→        if (!floor) return;
559→        if (selectedType === 'wall') {
560→          dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
561→        } else if (selectedType === 'door') {
562→          dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
563→        } else if (selectedType === 'window') {
564→          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
565→        } else if (selectedType === 'column') {
566→          dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
567→        } else if (selectedType === 'fixture') {
568→          dispatch({ type: 'FIXTURE_DELETE', floorId: activeFloorId, fixtureId: selectedId });
569→        } else if (selectedType === 'beam') {
570→          dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
571→        } else if (selectedType === 'stair') {
572→          dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
573→        } else if (selectedType === 'landing') {
574→          dispatch({ type: 'LANDING_DELETE', floorId: activeFloorId, landingId: selectedId });
575→        } else if (selectedType === 'annotation') {
576→          dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
577→        } else if (selectedType === 'slab') {
578→          dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId, slabId: selectedId });
579→        } else if (selectedType === 'railing') {
580→          dispatch({ type: 'RAILING_DELETE', floorId: activeFloorId, railingId: selectedId });
581→        } else if (selectedType === 'sectionCut') {
582→          dispatch({ type: 'SECTION_DELETE', floorId: activeFloorId, sectionId: selectedId });
583→        } else if (selectedType === 'room') {
584→          dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
585→        }
586→        editorDispatch({ type: 'DESELECT' });
587→      }
588→    },
589→
590→    getCursor(toolState) {
591→      if (toolState.dragType === 'marquee') return 'crosshair';
592→      if (toolState.dragging) return 'grabbing';
593→      return 'default';
594→    },
595→  };
596→}
