 60→function useUnits() {
 61→  const [unit, setUnit] = useState('mm');
 62→  const isMm = unit === 'mm';
 63→  return {
 64→    unit,
 65→    setUnit,
 66→    suffix: isMm ? 'mm' : 'm',
 67→    toDisplay: (mm) => isMm ? +mm.toFixed(1) : +(mm / 1000).toFixed(4),
 68→    fromDisplay: (v) => isMm ? v : v * 1000,
 69→    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
 70→  };
 71→}
